def icon(name: str, cls: str = "w-4 h-4") -> Markup:
    """Render a Heroicon as inline SVG. Use as a Jinja global:
        {{ icon('plus') }}
        {{ icon('trash', cls='w-5 h-5 text-red-600') }}
    """
    path = _PATHS.get(name)
    if path is None:
        return Markup(f'<span class="{cls}" data-missing-icon="{name}"></span>')
    return Markup(
        f'<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" '
        f'fill="currentColor" class="{cls} inline-block shrink-0" '
        f'aria-hidden="true">{path}</svg>'
    )
